import{_ as o,o as r,c as a,ai as l}from"./chunks/framework.DMjte4z8.js";const c=JSON.parse('{"title":"技能编辑器与自定义技能","description":"","frontmatter":{"title":"技能编辑器与自定义技能","category":"object-editor","updated":"2026-05-08T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.78,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/threads/how-to-add-a-new-ability-to-the-object-editor-and-use-it-in-your-map.363666/","https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=48088"]},"headers":[],"relativePath":"object-editor/技能编辑器与自定义技能.md","filePath":"object-editor/技能编辑器与自定义技能.md","lastUpdated":1778216780000}'),i={name:"object-editor/技能编辑器与自定义技能.md"};function e(n,t,s,d,g,h){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="技能编辑器与自定义技能" tabindex="-1">技能编辑器与自定义技能 <a class="header-anchor" href="#技能编辑器与自定义技能" aria-label="Permalink to “技能编辑器与自定义技能”">​</a></h1><h2 id="技能编辑器基础入门" tabindex="-1">技能编辑器基础入门 <a class="header-anchor" href="#技能编辑器基础入门" aria-label="Permalink to “技能编辑器基础入门”">​</a></h2><p>本节将带你认识魔兽争霸3地图编辑器中的技能编辑器界面，并学会如何查看和修改已有的技能。完成本节后，你将能够独立打开技能编辑器，找到你想要的技能，并了解每个技能的基本参数含义。</p><h3 id="认识技能编辑器界面" tabindex="-1">认识技能编辑器界面 <a class="header-anchor" href="#认识技能编辑器界面" aria-label="Permalink to “认识技能编辑器界面”">​</a></h3><p>技能编辑器在魔兽争霸3世界编辑器（World Editor）中被称为&quot;对象编辑器&quot;的一个分支。要打开它，你需要先启动世界编辑器，然后在顶部菜单栏找到 <strong>&quot;模块&quot;（Modules）</strong>，在下拉菜单中点击 <strong>&quot;对象编辑器&quot;（Object Editor）</strong> 即可打开[^1]。</p><p>打开后，你会看到界面左侧有一个分层列表，分别包含：</p><ul><li><strong>技能（Abilities）</strong> — 单位可以使用的主动或被动技能</li><li><strong>魔法效果（Buffs/Effects）</strong> — 技能施加的状态效果</li><li><strong>单位（Units）</strong> — 地图中的所有单位类型</li><li><strong>物品（Items）</strong> — 物品及其附带的技能</li></ul><blockquote><p><strong>💡 新手提示</strong>：如果你在列表中没有看到&quot;技能&quot;选项，可能是因为你点击的是&quot;魔法效果&quot;或其他类别。仔细检查左侧面板的标签页，确保你在&quot;技能&quot;分类下。</p></blockquote><h3 id="技能编辑器的基本操作" tabindex="-1">技能编辑器的基本操作 <a class="header-anchor" href="#技能编辑器的基本操作" aria-label="Permalink to “技能编辑器的基本操作”">​</a></h3><ol><li><p><strong>第一步：打开技能列表</strong> — 在对象编辑器中点击左侧的 <strong>&quot;技能&quot;</strong> 分类，你会看到编辑器中列出了所有可用的技能模板[^2]。</p></li><li><p><strong>第二步：搜索特定技能</strong> — 在技能列表上方的搜索框中输入技能名称（如&quot;闪电链&quot;或&quot;Thunder Clap&quot;），可以快速定位到你想要的技能[^1]。</p></li><li><p><strong>第三步：查看技能详情</strong> — 点击任意技能后，右侧会显示该技能的所有可修改参数。常见的参数包括：</p><ul><li><strong>科技等级（Tech Level）</strong> — 解锁该技能需要的科技条件</li><li><strong>魔法消耗（Mana Cost）</strong> — 使用技能需要消耗的魔法值</li><li><strong>冷却时间（Cooldown）</strong> — 技能使用后的等待时间</li><li><strong>施法范围（Cast Range）</strong> — 技能可以作用的最大距离</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常发现技能在游戏中没有显示按钮图标。检查技能是否有一个小的问号图标在名称前面——如果有问号，说明这个技能没有按钮，通常是被设计为通过触发器（Trigger）而非手动施法来使用的[^2]。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 成功打开技能编辑器（对象编辑器）</li><li>✅ 在技能列表中找到你需要的技能</li><li>✅ 查看技能的基本参数设置</li><li>✅ 识别哪些技能有游戏内按钮、哪些没有</li></ul><h2 id="技能的基础概念" tabindex="-1">技能的基础概念 <a class="header-anchor" href="#技能的基础概念" aria-label="Permalink to “技能的基础概念”">​</a></h2><p>本节将带你认识 Warcraft III 技能系统的核心概念，理解不同类型技能的区别以及技能数据的基本结构。学完本节后，你将能够区分被动技能、主动技能和触发技能，并看懂技能编辑器中最常见的几个数据字段。</p><h3 id="技能类型与适用单位" tabindex="-1">技能类型与适用单位 <a class="header-anchor" href="#技能类型与适用单位" aria-label="Permalink to “技能类型与适用单位”">​</a></h3><p>在 War3 中，技能主要分为两大类：<strong>内置技能</strong>和<strong>触发技能</strong>。内置技能是暴雪预先编写好的技能逻辑，你只需在对象编辑器中调整参数即可使用；触发技能则需要你自己用触发器（一种可视化脚本系统）来编写技能逻辑[^1]。</p><h4 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>打开对象编辑器</strong> — 在顶部菜单栏点击&quot;对象编辑器&quot;按钮，或使用快捷键 F6[^2]</li><li><strong>展开技能分类</strong> — 在左侧目录树中找到&quot;技能&quot;文件夹，点击展开后会看到各种技能分类如&quot;一般&quot;、&quot;攻击&quot;、&quot;物品&quot;等[^1]</li><li><strong>了解图标含义</strong> — 如果某个技能名称前面显示一个小问号图标，说明这个技能在游戏中<strong>不会显示按钮</strong>，通常是被动效果或内部技能[^2]</li><li><strong>查看技能所属单位</strong> — 选中一个技能后，在右侧面板可以看到&quot;允许的 单位类型&quot;和&quot;要求的 单位类型&quot;字段，这决定了哪些单位可以使用该技能[^1]</li></ol><blockquote><p><strong>💡 新手提示</strong>：很多新手以为所有技能都能给任何单位用，其实每个技能都有&quot;适用单位&quot;的限制。在创建自定义技能前，先确认你的单位类型是否匹配。</p></blockquote><h3 id="技能数据结构解析" tabindex="-1">技能数据结构解析 <a class="header-anchor" href="#技能数据结构解析" aria-label="Permalink to “技能数据结构解析”">​</a></h3><p>每个技能在 War3 中都由多个&quot;字段&quot;组成，这些字段存储了技能的各种属性，比如伤害值、冷却时间、施法范围等。理解这些数据结构是制作自定义技能的基础[^1]。</p><h4 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>选择一个技能查看字段</strong> — 在对象编辑器中双击任意技能，右侧会显示该技能的所有可编辑字段[^1]</li><li><strong>认识常用字段</strong> — &quot;数据 - 基础等级&quot;决定技能初始等级，&quot;数据 - 冷却时间&quot;设置施放间隔，&quot;数据 - 施法范围&quot;决定有效距离[^1]</li><li><strong>理解字段数据类型</strong> — 数值类字段（如伤害）用数字表示，布尔类字段用&quot;是/否&quot;表示，字符串类字段可能需要引用其他文件[^1]</li><li><strong>注意未公开的技能</strong> — 有些暴雪内置技能没有直接显示在编辑器中，需要通过特殊方法提取相关文件才能使用[^1]</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忽略&quot;数据 - 等级&quot;和&quot;数据 - 基础等级&quot;的区别。&quot;基础等级&quot;是技能创建时默认的等级，而&quot;等级&quot;是技能最高可升到的等级。如果你想让技能只能升3级，应该设置&quot;等级&quot;为3，而不是&quot;基础等级&quot;。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该已经能够区分被动技能、主动技能和触发技能的不同用途，理解了技能与单位之间的关联，并认识了技能编辑器中最基础的几个数据字段。这些知识将帮助你在接下来的课程中顺利进行自定义技能的创建和调整。</p><h2 id="修改现有技能" tabindex="-1">修改现有技能 <a class="header-anchor" href="#修改现有技能" aria-label="Permalink to “修改现有技能”">​</a></h2><p>在本节中，你将学习如何在<strong>对象编辑器</strong>（Object Editor）中找到已有的技能，并修改它们的属性，比如伤害值、冷却时间等。完成学习后，你就能根据自己的地图需求，调整任意技能的数值了！</p><blockquote><p><strong>💡 新手提示</strong>：在 Warcraft III 中，&quot;对象编辑器&quot;是存储所有游戏单位、道具、技能的数据库。你可以把它想象成一个巨大的Excel表格，里面记录了每个技能的所有属性。</p></blockquote><h3 id="伤害与治疗数值设置" tabindex="-1">伤害与治疗数值设置 <a class="header-anchor" href="#伤害与治疗数值设置" aria-label="Permalink to “伤害与治疗数值设置”">​</a></h3><ol><li><strong>打开对象编辑器</strong> — 在顶部菜单栏点击&quot;模块&quot;（Modules）→ 选择&quot;对象编辑器&quot;（Object Editor）[^1]</li><li><strong>定位技能</strong> — 在左侧分类中找到&quot;技能&quot;（Abilities）文件夹，点击展开，然后找到你想修改的技能</li><li><strong>修改伤害数值</strong> — 找到&quot;数据&quot;（Data）选项卡中的&quot;伤害&quot;或&quot;治疗&quot;相关字段，点击数值并输入新数字[^1] <ul><li>伤害技能通常显示为&quot;Damage&quot;</li><li>治疗技能通常显示为&quot;Heal Amount&quot;</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手修改了技能数值后发现游戏里没有变化，这很可能是因为你修改的是模板技能，而不是实际在地图中使用的技能！建议先复制一个技能到你的自定义列表中再修改。</p></blockquote><h3 id="冷却时间与魔法消耗" tabindex="-1">冷却时间与魔法消耗 <a class="header-anchor" href="#冷却时间与魔法消耗" aria-label="Permalink to “冷却时间与魔法消耗”">​</a></h3><ol><li>在同一个技能属性界面中，向下滚动找到&quot;冷却时间&quot;（Cooldown）字段[^2]</li><li>输入新的冷却时间数值，单位是秒。例如输入&quot;5&quot;表示冷却5秒</li><li>找到&quot;魔法消耗&quot;（Mana Cost）字段，输入你想要的蓝耗数值</li><li>实时预览：按 F6 打开&quot;测试地图&quot;功能，可以在游戏中即时看到修改效果</li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你看到某个技能旁边有个<strong>问号图标</strong>（?），说明这个技能在游戏中没有图标，无法直接给单位使用，但可以用于触发器逻辑[^2]。</p></blockquote><h3 id="技能范围与持续时间" tabindex="-1">技能范围与持续时间 <a class="header-anchor" href="#技能范围与持续时间" aria-label="Permalink to “技能范围与持续时间”">​</a></h3><ol><li>找到&quot;施法范围&quot;（Cast Range）或&quot;作用范围&quot;（Area of Effect）字段[^1] <ul><li>&quot;Cast Range&quot; = 施法距离（你必须离目标多近才能施放）</li><li>&quot;Area of Effect&quot; = 作用范围（技能生效的区域大小）</li></ul></li><li>修改&quot;持续时间&quot;（Duration）字段，这决定了技能效果维持多久</li><li>部分技能还有&quot;缓冲时间&quot;（Buff Duration）等子字段，也需要根据需求调整</li></ol><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 打开对象编辑器并定位到目标技能</li><li>✅ 修改技能的基础伤害/治疗数值</li><li>✅ 调整冷却时间和魔法消耗</li><li>✅ 设置技能的施法距离和持续时间</li></ul><p>建议先从一个简单的技能（如&quot;闪电链&quot;或&quot;治疗波&quot;）开始练习，熟练后再尝试修改复杂的技能！</p><h2 id="创建自定义技能" tabindex="-1">创建自定义技能 <a class="header-anchor" href="#创建自定义技能" aria-label="Permalink to “创建自定义技能”">​</a></h2><p>本节将教你使用<strong>复制修改法</strong>在 Warcraft III 编辑器中创建自定义技能。学完本节后，你将能够基于游戏自带的技能进行修改，创造属于你自己的独特技能！</p><h3 id="复制修改法创建技能" tabindex="-1">复制修改法创建技能 <a class="header-anchor" href="#复制修改法创建技能" aria-label="Permalink to “复制修改法创建技能”">​</a></h3><blockquote><p><strong>💡 为什么先复制再修改？</strong> 从零开始创建技能需要设置几十个参数，很容易出错。复制一个已有的类似技能再修改，可以大大降低出错概率，同时保留原技能的正确基础设置。</p></blockquote><p><strong>操作步骤：</strong></p><ol><li><p><strong>打开对象编辑器</strong> — 在顶部菜单栏点击「触发器编辑器」旁边的「对象编辑器」按钮[^1]</p></li><li><p><strong>展开技能分类</strong> — 在左侧目录中找到「技能」文件夹，点击展开，你会看到很多技能（如「风暴之锤」「神圣之光」等）</p></li><li><p><strong>选择一个基础技能</strong> — 右键点击一个与你想要创建的技能类型相似的技能，点击「复制」[^1]</p></li><li><p><strong>粘贴并重命名</strong> — 在技能列表空白处右键，点击「粘贴」，然后右键新技能选择「重命名」为你的自定义技能名称</p></li><li><p><strong>修改技能属性</strong> — 选中你的新技能，在右侧面板中可以修改以下关键参数：</p><ul><li><strong>数据 - 伤害值</strong>（影响技能造成的伤害）</li><li><strong>数据 - 施法时间</strong>（读条时间，设为0为瞬发）</li><li><strong>数据 - 冷却时间</strong>（使用后多久能再次使用）</li><li><strong>数据 - 魔法消耗</strong>（使用需要多少魔法值）</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只改了名字就以为完成了，但实际上技能的各项数值还是原技能的数据！一定要仔细检查「数据」标签页下的所有参数。</p></blockquote><h3 id="技能图标与热键设置" tabindex="-1">技能图标与热键设置 <a class="header-anchor" href="#技能图标与热键设置" aria-label="Permalink to “技能图标与热键设置”">​</a></h3><p><strong>操作步骤：</strong></p><ol start="6"><li><p><strong>设置技能图标</strong> — 在技能属性中找到「艺术 - 头像」字段，点击右侧的放大镜图标，从中选择一个图标图片</p></li><li><p><strong>设置热键</strong> — 找到「热键」字段，输入一个字母（如 Q、W、E 等）作为快捷键[^2]</p></li><li><p><strong>检查按钮位置</strong> — 在「按钮位置 - X坐标」和「按钮位置 - Y坐标」中设置图标在技能栏中的位置（0-5）</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你在对象编辑器中看到技能名称前面有一个<strong>小问号图标</strong>，说明这个技能在游戏中<strong>不会显示按钮</strong>，无法被玩家使用[^2]。遇到这种情况，请换一个没有问号的技能作为基础来复制。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忽略「按钮位置」的设置！如果设置为(0,0)但该位置已被其他技能占用，会导致技能无法正常显示在技能栏中。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看到你创建的自定义技能出现在「单位」编辑器中某个单位的技能列表里。按下 F6 测试地图，按下你设置的热键就能使用新技能了！恭喜你完成了第一个自定义技能！🎉</p><h2 id="技能测试与调试" tabindex="-1">技能测试与调试 <a class="header-anchor" href="#技能测试与调试" aria-label="Permalink to “技能测试与调试”">​</a></h2><p>本节将学习如何在地图中实际测试你创建的技能，以及遇到问题时如何排查解决。学完本节后，你将能够独立验证技能是否正常工作，并解决一些常见的技能显示或功能问题。</p><h3 id="地图中测试技能" tabindex="-1">地图中测试技能 <a class="header-anchor" href="#地图中测试技能" aria-label="Permalink to “地图中测试技能”">​</a></h3><ol><li><p><strong>保存你的地图</strong> — 在 World Editor 中点击菜单「文件」→「保存」，或直接按快捷键 <code>Ctrl + S</code>。测试前一定要先保存，否则改动不会生效[^1]。</p></li><li><p><strong>打开测试模式</strong> — 点击编辑器顶部工具栏的绿色「测试地图」按钮（或者按 <code>F10</code>）。World Editor 会自动启动 Warcraft III 游戏并加载你的地图[^1]。</p></li><li><p><strong>进入游戏测试技能</strong> — 在游戏中创建一个拥有该技能的单位（你之前在对象编辑器里设置的单位）。将单位选中，按对应的快捷键或点击技能图标来释放技能。</p></li><li><p><strong>观察技能效果</strong> — 注意观察以下内容：</p><ul><li>技能图标是否正常显示？（如果图标前面有问号 ❓，说明这个技能在游戏中不会显示按钮[^2]）</li><li>技能释放时是否有特效？</li><li>技能是否对目标产生了预期效果？</li></ul></li><li><p><strong>退出测试返回编辑</strong> — 按 <code>Esc</code> 键退出游戏，World Editor 会重新显示，你可以继续修改。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：第一次测试时，建议先用「测试地图」功能，而不要直接打开完整的 Warcraft III。因为测试模式启动更快，而且如果地图有严重错误导致游戏崩溃，也更容易排查问题。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手发现技能在游戏里完全不显示，却找不到原因。很可能是因为技能图标旁边有一个小问号「❓」。有问号意味着这个技能<strong>根本没有按钮</strong>，它只能通过触发器代码来调用，无法手动释放[^2]。遇到这种情况，你需要换一个没有问号的技能作为基础。</p></blockquote><h3 id="常见问题与解决方案" tabindex="-1">常见问题与解决方案 <a class="header-anchor" href="#常见问题与解决方案" aria-label="Permalink to “常见问题与解决方案”">​</a></h3><table tabindex="0"><thead><tr><th>问题现象</th><th>可能原因</th><th>解决方法</th></tr></thead><tbody><tr><td>技能图标显示为问号</td><td>选择的原技能没有图标资源</td><td>换一个没有问号的技能模板[^2]</td></tr><tr><td>技能按钮不显示</td><td>技能被放在了技能书中</td><td>从技能书移除，或设置快捷键</td></tr><tr><td>释放技能没效果</td><td>技能数据未正确设置</td><td>检查「数据」面板中的数值（如施法范围、伤害值）</td></tr><tr><td>游戏启动报错</td><td>地图文件损坏</td><td>尝试「另存为」新文件，或撤销最近的修改</td></tr></tbody></table><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经成功在游戏中测试了你的自定义技能。如果发现问题，回到对象编辑器或触发器中修改，然后再次点击「测试地图」按钮重新验证。调试是一个反复尝试的过程，不要气馁——每次测试都会让你更接近一个完美运行的技能！</p><h2 id="技能平衡与优化" tabindex="-1">技能平衡与优化 <a class="header-anchor" href="#技能平衡与优化" aria-label="Permalink to “技能平衡与优化”">​</a></h2><p>本节将学习如何调整技能的各项数值使游戏体验更公平有趣，以及如何将技能与触发器结合实现更强大的效果。学完本节后，你将能够制作出数值合理、玩法多样的自定义技能。</p><h3 id="技能数值平衡基础" tabindex="-1">技能数值平衡基础 <a class="header-anchor" href="#技能数值平衡基础" aria-label="Permalink to “技能数值平衡基础”">​</a></h3><p>在 Warcraft III 中，每个技能的强大程度主要由三个核心数值决定：伤害值、冷却时间和魔法消耗。这三者之间的关系就像三角形的三个顶点，相互影响、相互制约。[^1]</p><ol><li><strong>找到目标技能</strong> — 打开对象编辑器（Object Editor），在左侧列表中展开“技能”选项，找到你想要调整数值的技能[^1]</li><li><strong>查看技能数据</strong> — 点击技能后，在右侧“数值”标签页中可以看到“数据 - 正常”下的各项参数</li><li><strong>调整基础数值</strong> — 找到以下关键字段： <ul><li><strong>伤害值</strong>（Damage）— 技能造成的直接伤害数字</li><li><strong>冷却时间</strong>（Cooldown）— 技能使用后需要等待多少秒才能再次使用</li><li><strong>魔法消耗</strong>（Mana Cost）— 使用技能需要消耗多少魔法值</li></ul></li><li><strong>理解平衡关系</strong> — 作为新手，你可以记住这个简单规律：伤害越高 → 冷却时间应越长 或 魔法消耗应越高</li></ol><blockquote><p><strong>💡 新手提示</strong>：建议先设置一个“基准技能”，比如让一个技能的伤害为100、冷却为10秒、耗蓝为50，然后再基于这个基准按比例调整其他技能的数值，这样更容易保持整体平衡。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手往往只关注伤害数值而忽略冷却时间和耗蓝。一个超高伤害但冷却很短的技能会严重破坏游戏平衡，记得三者要同时考虑。</p></blockquote><h3 id="技能与触发器的结合" tabindex="-1">技能与触发器的结合 <a class="header-anchor" href="#技能与触发器的结合" aria-label="Permalink to “技能与触发器的结合”">​</a></h3><p>对象编辑器中的技能功能有限，如果想实现更复杂的逻辑（比如技能命中后附带减速效果、或者根据目标血量造成额外伤害），就需要借助<strong>触发器</strong>（Trigger）来实现。[^2]</p><p>触发器你可以理解为“一套自动执行的规则”：当某个事件发生时（比如技能被施放），触发器会执行你预设的一系列动作。</p><ol><li><strong>打开触发器编辑器</strong> — 在 World Editor 顶部菜单点击“触发器编辑器”（Trigger Editor）按钮</li><li><strong>创建一个新触发器</strong> — 点击左上角“新建触发器”按钮，为它起一个容易识别的名字，如“火球术增强”</li><li><strong>设置触发条件</strong> — 在触发器编辑区域，点击“事件”部分，添加一个新事件。选择“单位 - 单位开始施放技能”</li><li><strong>添加条件判断</strong> — 点击“条件”部分，添加条件：检查正在施放的技能是否是你想要增强的技能</li><li><strong>编写动作逻辑</strong> — 在“动作”部分，添加你想要实现的额外效果，比如： <ul><li>对目标施加减速效果</li><li>造成额外伤害</li><li>显示特效</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：触发器的逻辑顺序很重要！动作是按从上到下的顺序执行的，就像流水线一样。如果你先写“造成伤害”再写“显示特效”，游戏会先处理伤害再播放特效。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记在触发器中添加“等待”或“应用到单位组”这类循环逻辑，导致技能效果只对单个目标生效。制作范围技能时，记得使用“单位组 - 选取范围内所有单位”这类函数。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该已经掌握了技能数值平衡的基本思路——通过调整伤害、冷却和耗蓝三者之间的关系来保持游戏公平性。同时，你也学会了如何通过触发器为技能添加更丰富的效果。如果想要进一步提升，建议先制作一套包含3-5个技能的完整技能树，然后邀请朋友测试并收集反馈，根据实际体验反复微调数值。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/how-to-add-a-new-ability-to-the-object-editor-and-use-it-in-your-map.363666/" target="_blank" rel="noreferrer">How to add a new ability to the Object Editor and use it in your map</a> — accessed 2026-05-08 [^2]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=48088" target="_blank" rel="noreferrer">Abilities - Introduction - Warcraft III World Editor</a> — accessed 2026-05-08</p>',84)])])}const p=o(i,[["render",e]]);export{c as __pageData,p as default};
